CREATE TYPE "EnterpriseDocumentStatus" AS ENUM ('DRAFT','IN_REVIEW','APPROVED','PUBLISHED','ARCHIVED');
CREATE TYPE "EnterpriseDocumentVisibility" AS ENUM ('ORGANIZATION','RESTRICTED','PRIVATE');
CREATE TYPE "DocumentCollaboratorRole" AS ENUM ('OWNER','EDITOR','REVIEWER','VIEWER');
CREATE TYPE "DocumentReviewStatus" AS ENUM ('PENDING','APPROVED','CHANGES_REQUESTED','REJECTED');
CREATE TABLE "EnterpriseDocument" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"title" TEXT NOT NULL,"summary" TEXT,"status" "EnterpriseDocumentStatus" NOT NULL DEFAULT 'DRAFT',"visibility" "EnterpriseDocumentVisibility" NOT NULL DEFAULT 'ORGANIZATION',"allowedUserIds" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[],"ownerUserId" TEXT NOT NULL,"templateKey" TEXT,"currentVersionId" TEXT,"knowledgeDocumentId" TEXT,"publishedAt" TIMESTAMP(3),"archivedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "EnterpriseDocumentVersion" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"documentId" TEXT NOT NULL,"version" INTEGER NOT NULL,"content" TEXT NOT NULL,"changeSummary" TEXT,"metadata" JSONB NOT NULL DEFAULT '{}',"createdByUserId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "EnterpriseDocumentVersion_documentId_fkey" FOREIGN KEY ("documentId") REFERENCES "EnterpriseDocument"("id") ON DELETE CASCADE);
CREATE TABLE "DocumentCollaborator" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"documentId" TEXT NOT NULL,"userId" TEXT NOT NULL,"role" "DocumentCollaboratorRole" NOT NULL DEFAULT 'VIEWER',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "DocumentCollaborator_documentId_fkey" FOREIGN KEY ("documentId") REFERENCES "EnterpriseDocument"("id") ON DELETE CASCADE);
CREATE TABLE "DocumentReview" ("id" TEXT PRIMARY KEY,"organizationId" TEXT NOT NULL,"documentId" TEXT NOT NULL,"versionId" TEXT NOT NULL,"requestedByUserId" TEXT NOT NULL,"reviewerUserId" TEXT NOT NULL,"status" "DocumentReviewStatus" NOT NULL DEFAULT 'PENDING',"comments" TEXT,"dueAt" TIMESTAMP(3),"decidedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "DocumentReview_documentId_fkey" FOREIGN KEY ("documentId") REFERENCES "EnterpriseDocument"("id") ON DELETE CASCADE,CONSTRAINT "DocumentReview_versionId_fkey" FOREIGN KEY ("versionId") REFERENCES "EnterpriseDocumentVersion"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "EnterpriseDocumentVersion_documentId_version_key" ON "EnterpriseDocumentVersion"("documentId","version");
CREATE UNIQUE INDEX "DocumentCollaborator_documentId_userId_key" ON "DocumentCollaborator"("documentId","userId");
CREATE INDEX "EnterpriseDocument_organizationId_status_updatedAt_idx" ON "EnterpriseDocument"("organizationId","status","updatedAt");
CREATE INDEX "DocumentReview_organizationId_reviewerUserId_status_idx" ON "DocumentReview"("organizationId","reviewerUserId","status");
